@_cdecl("_nitro_ar_register_detectedPackages_stream")
public func _nitro_ar_register_detectedPackages_stream(
    _ dartPort: Int64,
    _ emitCb: @convention(c) (Int64, UnsafeMutablePointer<UInt8>?) -> Bool
) {
    NitroArRegistry._detectedPackagesCancellables[dartPort] =
        NitroArRegistry.impl?.detectedPackages.sink { item in
            let raw = item.toNative()
            if !emitCb(dartPort, raw) {
                if let raw { free(UnsafeMutableRawPointer(raw)) }
                NitroArRegistry._detectedPackagesCancellables.removeValue(forKey: dartPort)?.cancel()
            }
        }
}

@_cdecl("_nitro_ar_release_detectedPackages_stream")
public func _nitro_ar_release_detectedPackages_stream(_ dartPort: Int64) {
    NitroArRegistry._detectedPackagesCancellables[dartPort]?.cancel()
    NitroArRegistry._detectedPackagesCancellables.removeValue(forKey: dartPort)
}
